:root {
    --primary-color: #5c6bc0;
    --secondary-color: #ff69b4;
    --bg-color: #121212;
    --text-color: #ffffff;
    --font-heading: 'Space Grotesk', sans-serif;
    --font-body: 'Inter', sans-serif;
    --spacing-scale: 1.2;
    --glassmorphism-blur: 10px;
    --glassmorphism-opacity: 0.5;
}

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    background-color: var(--bg-color);
    color: var(--text-color);
    line-height: var(--spacing-scale);
    overflow-x: hidden;
}

.navbar {
    background-color: var(--primary-color);
    padding: 1rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    position: sticky;
    top: 0;
    z-index: 1000;
}

.navbar ul {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
}

.navbar li {
    margin-right: 20px;
}

.navbar a {
    color: var(--text-color);
    text-decoration: none;
}

.hero-section {
    background-image: linear-gradient(to bottom, var(--primary-color), var(--secondary-color));
    background-size: 100% 300px;
    background-position: 0% 100%;
    height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    color: var(--text-color);
    animation: animateBackground 10s infinite;
}

@keyframes animateBackground {
    0% {
        background-position: 0% 100%;
    }
    100% {
        background-position: 100% 100%;
    }
}

.features-section {
    padding: 2rem;
}

.features-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
}

.feature-card {
    background-color: var(--bg-color);
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

.feature-card img {
    width: 50px;
    height: 50px;
    margin: 10px;
}

.how-it-works-section {
    padding: 2rem;
}

.how-it-works-steps {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.how-it-works-step {
    background-color: var(--bg-color);
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
    margin: 20px;
}

.how-it-works-step img {
    width: 50px;
    height: 50px;
    margin: 10px;
}

.testimonials-section {
    padding: 2rem;
}

.testimonials-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
}

.testimonial-card {
    background-color: var(--bg-color);
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

.testimonial-card img {
    width: 50px;
    height: 50px;
    margin: 10px;
}

.pricing-section {
    padding: 2rem;
}

.pricing-plans {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.pricing-plan {
    background-color: var(--bg-color);
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
    margin: 20px;
}

.faq-section {
    padding: 2rem;
}

.faq-questions {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.faq-question {
    background-color: var(--bg-color);
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
    margin: 20px;
}

footer {
    background-color: var(--primary-color);
    padding: 1rem;
    text-align: center;
    color: var(--text-color);
}

.glass-card {
    background: rgba(255, 255, 255, 0.1);
    border-radius: 16px;
    box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.3);
}

@media (max-width: 768px) {
    .features-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 480px) {
    .features-grid {
        grid-template-columns: repeat(1, 1fr);
    }
}

